import type { Request, Response } from 'express';
import { productService as ProductService } from '@services/products';
import { successResponse } from '@utils/response';
import type { SearchProductsRequest } from '@types';


/**
 * Query parameters generated by the search form (they are the same as SearchOrdersRequest keys)
 */
export type IGetProductsQuery = Partial<Record<keyof SearchProductsRequest, string>>;

/**
 * GET /products
 * List/search products via query parameters.
 * Admin sees all products (including inactive/deleted); public sees only active ones.
 */
export const getProducts = (
    request: Request<{ page?: string }, unknown, SearchProductsRequest, IGetProductsQuery>,
    response: Response
) => {
    const page = request.body.page ?? request.query.page ?? '1'
    const pageSize = request.body.pageSize ?? request.query.pageSize ?? process.env.NODE_SETTINGS_PAGINATION_PAGE_SIZE ?? '10'
    const minPrice = request.body.minPrice ?? request.query.minPrice ? Number(request.body.minPrice ?? request.query.minPrice) : undefined;
    const maxPrice = request.body.minPrice ?? request.query.minPrice ? Number(request.body.minPrice ?? request.query.minPrice) : undefined;

    return ProductService.search({
        id: request.body.id ?? request.query.id,
        page: page ? Number(page) : undefined,
        pageSize: pageSize ? Number(pageSize) : undefined,
        text: request.body.text ?? request.query.text,
        minPrice,
        maxPrice,
        // Only admin can see non-active products
    }, request.user?.admin === true).then((result) => {
        successResponse(response, result);
    });
};

